gsap.registerPlugin(MorphSVGPlugin)

document.querySelectorAll('.dl-parachute').forEach(button => {
    let circle = button.querySelector('.circle path'),
        arrow = button.querySelector('.arrow path'),
        line = new Proxy({
            y: null
        }, {
            set(target, key, value) {
                target[key] = value
                if (target.y !== null) {
                    button.querySelector('.line').innerHTML = getPath(target.y, .2)
                }
                return true
            },
            get(target, key) {
                return target[key]
            }
        }),
        number = button.querySelector('.number span'),
        count = { number: 0 }
    line.y = 64.5

    button.addEventListener('click', e => {
        e.preventDefault()

        if (button.classList.contains('active')) {
            return
        }

        button.classList.add('active')

        gsap.timeline().to(circle, {
            morphSVG: 'M10 120.5C11.5 120.5 29.1914 120.5 61.5 120.5C78.5 120.5 108.054 120.777 140.5 120.5C172.67 120.225 201.5 120.5 218.5 120.5C250.397 120.5 268.5 120.5 270 120.5',
            duration: .15,
            onComplete() {
                gsap.set(button, {
                    '--circle-opacity': 0,
                    '--line-opacity': 1
                })
            }
        }).to(button, {
            '--svg-y': '120px',
            '--arrow-y': '44px',
            duration: .15
        }, 0).to(button, {
            '--arrow-y': '-72px',
            duration: .3,
            ease: 'power1.out'
        }).to(button, {
            '--arrow-y': '40px',
            '--line-progress': '0px',
            duration: 3,
            delay: .15,
            onStart() {
                gsap.to(button, {
                    '--line-progress-o': 1
                })
            }
        }).to(count, {
            number: 100,
            roundProps: 'number',
            duration: 3,
            onUpdate: () => number.innerHTML = count.number
        }, .6).to(button, {
            '--parachute-o': 0,
            '--parachute-y': '12px',
            duration: .2
        }).to(button, {
            '--arrow-y': '20px',
            duration: .7,
            ease: 'elastic.out(1, .8)'
        })

        gsap.to(button, {
            '--parachute-s': 1,
            '--number-o': 1,
            '--number-y': '0px',
            duration: .2,
            delay: .4
        })

        gsap.to(button, {
            ease: 'linear',
            keyframes: [{
                '--arrow-r': '190deg',
                '--arrow-x': '-12px',
                duration: .6,
                delay: .6
            }, {
                '--arrow-r': '170deg',
                '--arrow-x': '12px',
                duration: .6
            }, {
                '--arrow-r': '185deg',
                '--arrow-x': '-6px',
                duration: .7
            }, {
                '--arrow-r': '180deg',
                '--arrow-x': '0px',
                duration: .5
            }]
        })

        gsap.to(button, {
            '--arrow-r': '180deg',
            duration: .3
        })

        gsap.to(line, {
            keyframes: [{
                y: 24,
                duration: .15,
                delay: .125
            }, {
                y: 64.5,
                duration: .8,
                ease: 'elastic.out(1, .5)'
            }]
        })

        gsap.to(button, {
            '--success-o': 1,
            '--success-y': '0px',
            duration: .25,
            delay: 3.825
        })

        gsap.to(arrow, {
            morphSVG: 'M28.5858 10.0503C29.3669 9.2692 30.6332 9.2692 31.4142 10.0503L42.5 21.136C43.8807 22.5167 43.8807 24.7553 42.5 26.136C41.1193 27.5168 38.8807 27.5167 37.5 26.136L31.4142 20.0502C30.6332 19.2692 29.3669 19.2692 28.5858 20.0503L10.5 38.136C9.11931 39.5167 6.88073 39.5168 5.50002 38.136C4.11931 36.7553 4.11931 34.5167 5.50002 33.136L28.5858 10.0503Z',
            duration: .2,
            delay: 3.8
        })

    })
})


function getPoint(point, i, a, smoothing) {
    let cp = (current, previous, next, reverse) => {
        let p = previous || current,
            n = next || current,
            o = {
                length: Math.sqrt(Math.pow(n[0] - p[0], 2) + Math.pow(n[1] - p[1], 2)),
                angle: Math.atan2(n[1] - p[1], n[0] - p[0])
            },
            angle = o.angle + (reverse ? Math.PI : 0),
            length = o.length * smoothing;
        return [current[0] + Math.cos(angle) * length, current[1] + Math.sin(angle) * length];
    },
        cps = cp(a[i - 1], a[i - 2], point, false),
        cpe = cp(point, a[i - 1], a[i + 1], true);
    return `C ${cps[0]},${cps[1]} ${cpe[0]},${cpe[1]} ${point[0]},${point[1]}`;
}

function getPath(update, smoothing) {
    let points = [
        [10, 64.5],
        [140, update],
        [270, 64.5]
    ],
        d = points.reduce((acc, point, i, a) => i === 0 ? `M ${point[0]},${point[1]}` : `${acc} ${getPoint(point, i, a, smoothing)}`, '');
    return `<path d="${d}" /><path class="progress" d="${d}" />`;
}

style.css:
html {
  box-sizing: border-box;
  -webkit-font-smoothing: antialiased;
}

* {
  box-sizing: inherit;
}

*:before,
*:after {
  box-sizing: inherit;
}

body {
  overflow: hidden;
  min-height: 100vh;
  font-family: "Inter";
  display: flex;
  justify-content: center;
  align-items: center;
  background: white;
}

.dl-parachute {
  --color-text: #275EFE;
  --color-icon: #275EFE;
  --color-line: #275EFE;
  --svg-y: 0px;
  --arrow-x: 0px;
  --arrow-y: 2px;
  --arrow-r: 0deg;
  --line-opacity: 0;
  --circle-opacity: 1;
  --parachute-o: 1;
  --parachute-y: 0px;
  --parachute-s: 0;
  --line-progress-o: 0;
  --line-progress: 260px;
  --success-y: 12px;
  --success-o: 0;
  --number-y: 12px;
  --number-o: 0;
  -webkit-tap-highlight-color: transparent;
  -webkit-appearance: none;
  outline: none;
  background: none;
  border: none;
  padding: 0;
  margin: 0;
  cursor: pointer;
  font-size: 14px;
  font-weight: 600;
  font-family: "Inter";
  position: relative;
  width: 120px;
  height: 120px;
}

.dl-parachute svg {
  display: block;
  pointer-events: none;
}

.dl-parachute svg.circle,
.dl-parachute svg.line {
  width: 280px;
  height: 124px;
  position: absolute;
  left: -80px;
  stroke-width: 3px;
  stroke-linecap: round;
  stroke: var(--color-line);
  fill: none;
}

.dl-parachute svg.circle {
  top: -2px;
  opacity: var(--circle-opacity);
  transform: translateY(var(--svg-y)) rotate(180deg);
}

.dl-parachute svg.line {
  height: 128px;
  bottom: -65px;
  opacity: var(--line-opacity);
}

.dl-parachute svg.line .progress {
  stroke-width: 6px;
  stroke-dasharray: 260px;
  opacity: var(--line-progress-o);
  stroke-dashoffset: var(--line-progress);
}

.dl-parachute .arrow {
  position: absolute;
  left: 36px;
  top: 36px;
  transform: translate(var(--arrow-x), var(--arrow-y)) rotate(var(--arrow-r));
}

.dl-parachute .arrow .base {
  fill: var(--color-icon);
  width: 48px;
  height: 48px;
}

.dl-parachute .arrow .parachute {
  position: absolute;
  width: 28px;
  height: 32px;
  fill: var(--color-icon);
  left: 10px;
  bottom: -26px;
  transform-origin: 50% 0%;
  opacity: var(--parachute-o);
  transform: translateY(var(--parachute-y)) scale(var(--parachute-s));
}

.dl-parachute .number,
.dl-parachute .success {
  position: absolute;
  left: 0;
  right: 0;
  top: var(--t, 144px);
  text-align: center;
  color: var(--color-text);
  opacity: var(--o, var(--number-o));
  transform: translateY(var(--y, var(--number-y)));
}

.dl-parachute .success {
  --t: 12px;
  --o: var(--success-o);
  --y: var(--success-y);
}
